// mm/src/pages/account.js
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { clearAuth, getDisplayName, isSignedIn } from '../utils/auth';
import { listDocuments } from '../api/listDocuments';
import { uploadDocuments } from '../api/uploadDocuments';
import { downloadAndSaveDocuments } from '../api/downloadDocuments';

function formatBytes(bytes) {
  const n = Number(bytes || 0);
  if (!n) return '—';
  const units = ['B', 'KB', 'MB', 'GB'];
  let i = 0;
  let v = n;
  while (v >= 1024 && i < units.length - 1) {
    v /= 1024;
    i++;
  }
  return `${v.toFixed(i === 0 ? 0 : 2)} ${units[i]}`;
}

function formatUploadedAt(uploadedAt) {
  if (!uploadedAt) return '';
  try {
    const d = new Date(uploadedAt);
    if (Number.isNaN(d.getTime())) return String(uploadedAt);
    return d.toLocaleString();
  } catch {
    return String(uploadedAt);
  }
}

export default function AccountPage() {
  const nav = useNavigate();
  const fileRef = useRef(null);

  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(true);

  const [uploading, setUploading] = useState(false);
  const [uploadPct, setUploadPct] = useState(0);

  const [error, setError] = useState('');

  const displayName = useMemo(() => getDisplayName(), []);

  const refreshDocs = async () => {
    setError('');
    setLoading(true);

    try {
      const resp = await listDocuments();
      console.log('🧩 Account UI got:', resp);

      if (!resp?.success) {
        throw new Error(resp?.error || 'Failed to load documents');
      }

      const list = resp?.data?.documents || [];
      setDocs(list);
    } catch (e) {
      console.error(e);
      setDocs([]);
      setError(e?.message || 'Failed to load documents. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!isSignedIn()) {
      nav('/login', { replace: true });
      return;
    }
    refreshDocs();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const onLogout = () => {
    clearAuth();
    nav('/', { replace: true });
  };

  const onChooseFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setError('');
    setUploading(true);
    setUploadPct(0);

    try {
      const resp = await uploadDocuments(file, (pct) => setUploadPct(pct));
      if (resp?.success) {
        console.log('✅ Upload complete. Refreshing documents…', {
          filename: file?.name,
          size: file?.size,
        });
      }
      await refreshDocs();
    } catch (err) {
      console.error(err);
      setError('Upload failed. Please try again.');
    } finally {
      setUploading(false);
      setUploadPct(0);
      if (fileRef.current) fileRef.current.value = '';
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-slate-50 to-slate-100">
      <div className="mx-auto max-w-6xl px-4 py-10">
        {/* Header */}
        <div className="flex items-start justify-between gap-6">
          <div>
            <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight">
              Account
            </h1>
            <p className="mt-2 text-slate-500">
              Manage your documents and downloads.
              {displayName ? (
                <span className="ml-2 text-slate-400">
                  Signed in as: {displayName}
                </span>
              ) : null}
            </p>
          </div>

          <div className="flex items-center gap-3">
            <button
              type="button"
              onClick={() => nav('/workflow/start')}
              className="px-4 py-2 rounded-md border border-slate-200 bg-white text-slate-700 hover:bg-slate-50"
            >
              New Project
            </button>

            <button
              type="button"
              onClick={onLogout}
              className="px-4 py-2 rounded-md bg-slate-900 text-white hover:bg-slate-800"
            >
              Logout
            </button>
          </div>
        </div>

        {/* Upload card */}
        <div className="mt-8 bg-white border border-slate-200 rounded-2xl shadow-sm p-6">
          <div className="flex items-start justify-between gap-6">
            <div>
              <h2 className="text-2xl font-semibold text-slate-900">
                Upload a Document
              </h2>
              <p className="mt-1 text-sm text-slate-500">
                Upload manuscripts, covers, or supporting files.
              </p>
            </div>

            <div className="shrink-0">
              <input
                ref={fileRef}
                type="file"
                onChange={onChooseFile}
                className="hidden"
              />
              <button
                type="button"
                onClick={() => fileRef.current?.click()}
                disabled={uploading}
                className={[
                  'px-5 py-2 rounded-md text-white font-medium',
                  uploading ? 'bg-slate-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700',
                ].join(' ')}
              >
                {uploading ? 'Uploading…' : 'Upload'}
              </button>
            </div>
          </div>

          {uploading ? (
            <div className="mt-5">
              <div className="w-full bg-slate-100 rounded overflow-hidden">
                <div style={{ width: `${uploadPct}%` }} className="h-2 bg-blue-600 transition-all" />
              </div>
              <div className="mt-2 text-sm text-slate-600">Uploading: {uploadPct}%</div>
            </div>
          ) : null}

          {error ? <div className="mt-4 text-sm text-red-600">{error}</div> : null}
        </div>

        {/* Documents */}
        <div className="mt-8 bg-white border border-slate-200 rounded-2xl shadow-sm p-6">
          <div className="flex items-center justify-between gap-6">
            <div>
              <h2 className="text-2xl font-semibold text-slate-900">Your Documents</h2>
              <p className="mt-1 text-sm text-slate-500">View all documents associated with your account.</p>
            </div>

            <button
              type="button"
              onClick={refreshDocs}
              className="px-4 py-2 rounded-md border border-slate-200 bg-white text-slate-700 hover:bg-slate-50"
              disabled={loading}
            >
              Refresh
            </button>
          </div>

          <div className="mt-6">
            {loading ? (
              <div className="text-slate-500">Loading…</div>
            ) : docs.length === 0 ? (
              <div className="text-slate-500">No documents yet.</div>
            ) : (
              <div className="divide-y divide-slate-100">
                {docs.map((d) => {
                  const key = d.documentId || d.filePath || d.filename || Math.random();
                  const title = d.filename || d.name || `Document ${d.documentId || ''}`.trim();

                  return (
                    <div key={key} className="py-4 flex items-center justify-between gap-6">
                      <div className="min-w-0">
                        <div className="font-medium text-slate-900 truncate">{title}</div>
                        <div className="mt-1 text-xs text-slate-500">
                          <span className="mr-3">ID: {d.documentId || '—'}</span>
                          <span className="mr-3">Size: {formatBytes(d.size)}</span>
                          {d.uploadedAt ? (
                            <span>Uploaded: {formatUploadedAt(d.uploadedAt)}</span>
                          ) : null}
                        </div>
                      </div>

                      <div className="shrink-0 flex items-center gap-2">
                        <button
                          type="button"
                          onClick={() => downloadAndSaveDocuments(
                            d.documentId,
                            d.filename || d.name || `document_${d.documentId}`
                          )}
                          className="px-4 py-2 rounded-md bg-blue-600 text-white hover:bg-blue-700"
                          disabled={!d.documentId}
                        >
                          Download
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>

        <div className="mt-8 text-center text-xs text-slate-500">
          If you get redirected to login unexpectedly, your access token likely expired and refresh failed.
        </div>
      </div>
    </div>
  );
}
